module.exports = function(RED) {
    "use strict";

    function NeuralReLUNode(n) {
        RED.nodes.createNode(this, n);
        var node = this;

        node.on("input", function(msg, send, done) {
            var input = msg.payload;
            if (!Array.isArray(input)) {
                input = [input];
            }

            var output = input.map(function(v) { return Math.max(0, v); });

            msg.payload = output;
            msg.neural = msg.neural || {};
            msg.neural.type = "relu";
            msg.neural.shape = [output.length];

            var active = output.filter(function(v) { return v > 0; }).length;
            node.status({ fill: active > 0 ? "yellow" : "grey", shape: "dot", text: active + "/" + output.length + " active" });

            send(msg);
            done();
        });
    }

    RED.nodes.registerType("neural-relu", NeuralReLUNode);
};
